import { cn } from "@/lib/utils";
import {
  ImageOverlayClient,
  type ImageOverlayClientProps,
} from "@/registry/new-york/image-overlay/image-overlay-client";
import Image, { StaticImageData } from "next/image";
import React from "react";

export interface ImageOverlayProps extends ImageOverlayClientProps {
  src: string | StaticImageData;
  alt: string;
  sizes?: string;
  priority?: boolean;
  overlayClassName?: string;
  zoomOnHover?: boolean;
}

function ImageOverlay({
  src,
  alt,
  sizes,
  priority = false,
  className,
  overlayClassName,
  zoomOnHover = true,
  children,
  ...clientProps
}: ImageOverlayProps) {
  const isStaticImage = typeof src === "object";
  const staticAspectRatio = isStaticImage
    ? `${src.width} / ${src.height}`
    : undefined;

  return (
    <ImageOverlayClient
      className={cn(
        "relative aspect-square overflow-hidden cursor-pointer h-full w-full rounded-2xl",
        className
      )}
      style={{
        ...(staticAspectRatio ? { aspectRatio: staticAspectRatio } : {}),
        ...clientProps.style,
      }}
      {...clientProps}
    >
      <Image
        src={src}
        alt={alt}
        fill
        priority={priority}
        sizes={sizes}
        placeholder={isStaticImage && src.blurDataURL ? "blur" : undefined}
        className={cn(
          "object-cover transition-transform duration-300 ease-in-out",
          zoomOnHover && "group-data-[active=true]:scale-110"
        )}
      />

      {children && (
        <div
          className={cn(
            "absolute inset-0 transition-colors duration-300 bg-transparent group-data-[active=true]:bg-foreground/40",
            overlayClassName
          )}
        >
          <div className="absolute inset-0 transition-opacity duration-300 opacity-0 pointer-events-none group-data-[active=true]:opacity-100 group-data-[active=true]:pointer-events-auto">
            {children}
          </div>
        </div>
      )}
    </ImageOverlayClient>
  );
}

export { ImageOverlay };

"use client";

import { cn } from "@/lib/utils";
import { usePointerType } from "@/registry/new-york/image-overlay/use-pointer-type";
import React, { useCallback, useState } from "react";

export interface ImageOverlayClientProps
  extends React.ComponentProps<"div"> {
  onActiveChange?: (active: boolean) => void;
}

const ImageOverlayClient = React.forwardRef<
  HTMLDivElement,
  ImageOverlayClientProps
>(({ onActiveChange, onClick, onMouseEnter, onMouseLeave, className, children, ...props }, ref) => {
  const [active, setActive] = useState(false);
  const pointerType = usePointerType();

  const handleClick = useCallback(
    (e: React.MouseEvent<HTMLDivElement>) => {
      if (pointerType === "coarse") {
        const next = !active;
        setActive(next);
        onActiveChange?.(next);
      }
      onClick?.(e);
    },
    [pointerType, active, onClick, onActiveChange]
  );

  const handleMouseEnter = useCallback(
    (e: React.MouseEvent<HTMLDivElement>) => {
      if (pointerType === "fine") {
        setActive(true);
        onActiveChange?.(true);
      }
      onMouseEnter?.(e);
    },
    [pointerType, onMouseEnter, onActiveChange]
  );

  const handleMouseLeave = useCallback(
    (e: React.MouseEvent<HTMLDivElement>) => {
      if (pointerType === "fine") {
        setActive(false);
        onActiveChange?.(false);
      }
      onMouseLeave?.(e);
    },
    [pointerType, onMouseLeave, onActiveChange]
  );

  return (
    <div
      ref={ref}
      role="group"
      data-active={active}
      className={cn("group", className)}
      onClick={handleClick}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      {...props}
    >
      {children}
    </div>
  );
});
ImageOverlayClient.displayName = "ImageOverlayClient";

export { ImageOverlayClient };

"use client";

import { useSyncExternalStore } from "react";

type PointerType = "fine" | "coarse";

function getPointerType(): PointerType {
  if (typeof window === "undefined") return "fine";
  return window.matchMedia("(pointer: coarse)").matches ? "coarse" : "fine";
}

function subscribe(callback: () => void) {
  const mql = window.matchMedia("(pointer: coarse)");
  mql.addEventListener("change", callback);
  return () => mql.removeEventListener("change", callback);
}

export function usePointerType(): PointerType {
  return useSyncExternalStore(subscribe, getPointerType, () => "fine");
}
